        // Loop through the string backwards.
        for (int i = s.length() - 1; i >= 0; --i) {
          // Get the char at the current location.
          char c = s.charAt(i);

          // Add the char to the front of the list.
          chars.addFirst(c);
        }

        // Print out the result.
        System.out.print(chars);
      }
